const validator = require('../src/validator');

describe('Input Validation', () => {
  test('should sanitize SQL injection attempts', () => {
    const input = "'; DROP TABLE users--";
    const sanitized = validator.sanitizeSQL(input);
    expect(sanitized).not.toContain('DROP');
    expect(sanitized).not.toContain('--');
  });

  test('should validate phone number format', () => {
    expect(validator.isValidPhone('+1-555-123-4567')).toBe(true);
    expect(validator.isValidPhone('123')).toBe(false);
  });

  test('should reject XSS attempts', () => {
    const input = "<script>alert('xss')</script>";
    const sanitized = validator.sanitizeHTML(input);
    expect(sanitized).not.toContain('<script>');
    expect(sanitized).not.toContain('</script>');
  });

  test('should validate email format', () => {
    expect(validator.isValidEmail('test@example.com')).toBe(true);
  });
});

