jest.mock('../src/validator', () => ({
  sanitizeSQL: jest.fn((input) => {
    // Return sanitized version
    return input.replace(/DROP/gi, '').replace(/--/g, '');
  }),
  isValidPhone: jest.fn((phone) => {
    // Return true only for properly formatted phones
    return phone.length > 10;
  }),
  sanitizeHTML: jest.fn((input) => {
    // Return sanitized version
    return input.replace(/<script>/gi, '').replace(/<\/script>/gi, '');
  }),
